SELECT loan.uuid id, loan.order_no orderNo, loan.party_id partyId, loan.order_type orderType, loan.loan_amount loanAmount, loan.state state, loan.loan_currency loanCurrency, loan.pledge_currency pledgeCurrency, loan.pledge_amount pledgeAmount, loan.pledge_type pledgeType, loan.pledge_rate pledgeRate, loan.debt_amount debtAmount, loan.interest_amount interestAmount, loan.hourly_rate hourlyRate, loan.loan_cycle loanCycle, loan.create_time createTime, loan.expire_time expireTime, party.user_name username,party.user_code usercode,party.role_name rolename FROM t_loan_order loan LEFT JOIN tz_user party ON loan.party_id = party.user_id WHERE 1 = 1
AND (party.user_name like CONCAT('%', #{userParam}, '%') OR party.user_code like CONCAT('%', #{userParam}, '%') )
and loan.order_no =#{orderNo}
and loan.state =#{state}
and party.role_name =#{rolename}
AND loan.party_id in
#{item}
order by loan.CREATE_TIME desc
